(function(){
var script=document.currentScript;
var base=script&&script.src?script.src.replace(/search\.js(?:[?#].*)?$/,''):'';
function ready(fn){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',fn);}else{fn();}}
ready(function(){
var input=document.getElementById('til-doc-search');
var list=document.getElementById('til-doc-search-results');
if(!input||!list){return;}
function textFor(e){return(e.name+' '+e.group+' '+e.body+' '+e.info).toLowerCase();}
function clear(){while(list.firstChild){list.removeChild(list.firstChild);}}
function render(){
var q=input.value.trim().toLowerCase();
clear();
if(!q){return;}
var terms=q.split(/\s+/);
var shown=0;
for(var i=0;i<window.tilDocSearchEntries.length&&shown<20;i++){
var e=window.tilDocSearchEntries[i];
var text=textFor(e);
var ok=true;
for(var j=0;j<terms.length;j++){if(text.indexOf(terms[j])<0){ok=false;break;}}
if(!ok){continue;}
var li=document.createElement('li');
var a=document.createElement('a');
a.href=base+e.href;
a.textContent=e.name;
li.appendChild(a);
if(e.group){var g=document.createElement('span');g.className='doc-search-group';g.textContent=' '+e.group;li.appendChild(g);}
list.appendChild(li);
shown++;
}
if(shown===0){var empty=document.createElement('li');empty.textContent='No matches';list.appendChild(empty);}
}
input.addEventListener('input',render);
});
}());
